    arr = sorted(l)
    n = len(arr)

    for i in range(n - 2):
        if arr[i] > 0:  # since list is sorted, no need to continue
            break

        # optional: skip duplicate first elements to speed up (not required for correctness)
        if i > 0 and arr[i] == arr[i - 1]:
            continue

        left, right = i + 1, n - 1
        while left < right:
            s = arr[i] + arr[left] + arr[right]
            if s == 0:
                return True
            elif s < 0:
                left += 1
            else:
                right -= 1

    return False
